svg.script:
    
      // НАЛАШТУВАННЯ ТЕКСТУРИ
      const config = {
        gap: 2.5,              // Середня відстань між лініями 3,5
        baseStrokeWidth: 0.15, // Мінімальна товщина лінії
        varStrokeWidth: 0.45,  // Максимальна додаткова товщина ліній
        jitter: 1.1,           // Наскільки лінія відхиляється від прямої (кривизна) 1,8
        segmentLength: 8,     // Довжина одного сегмента кривої
        breakProbability: 0.98 // Ймовірність, що лінія ПЕРЕРВЕТЬСЯ (чим ближче до 1, тим більше коротких штрихів) 096
      };

      const container = document.getElementById('line-container');
      const width = 1000;
      const height = 1000;

      // Функція для генерації випадкового числа в діапазоні
      function random(min, max) {
        return Math.random() * (max - min) + min;
      }

      // Основна діагональ: з верхнього-правого в нижній-лівий
      function drawHatchLayer(step) {
        // Починаємо за межами екрану, щоб покрити весь простір
        for (let i = -width; i < height * 1.5; i += step * random(0.8, 1.2)) {
          let x = width + 50; // Починаємо справа
          let y = i;          // Зміщуємо старт по вертикалі

          // Створюємо новий елемент шляху (path)
          const path = document.createElementNS("http://www.w3.org/2000/svg", "path");
          
          // Випадкова товщина та прозорість для кожної лінії
          path.setAttribute("stroke-width", config.baseStrokeWidth + random(0, config.varStrokeWidth));
          path.setAttribute("stroke-opacity", random(0.3, 0.7));

          let d = `M ${x} ${y}`; // Початкова точка "Move To"

          // Малюємо лінію, поки вона не вийде за межі екрану
          while (x > -50 && y < height + 50) {
            // Визначаємо наступну точку сегмента
            const nextX = x - config.segmentLength * random(0.9, 1.1);
            const nextY = y + config.segmentLength * random(0.9, 1.1);

            // Додаємо "кривизну" через випадкові контрольні точки кривої Безьє (jitter)
            const ctrlX = x - config.segmentLength / 2 + (Math.random() - 0.5) * config.jitter * 6;
            const ctrlY = y + config.segmentLength / 2 + (Math.random() - 0.5) * config.jitter * 6;

            // Додаємо сегмент кривої "Quadratic Bézier Curveto"
            d += ` Q ${ctrlX} ${ctrlY}, ${nextX} ${nextY}`;

            // Оновлюємо поточну точку
            x = nextX;
            y = nextY;

            // ЛОГІКА ПЕРЕРВАННЯ (ефект відірваної руки)
            if (Math.random() > config.breakProbability) {
              // Робимо невеликий випадковий стрибок
              x -= random(1, 4);
              y += random(1, 4);
              // Починаємо новий під-шлях
              d += ` M ${x} ${y}`;
            }
          }

          path.setAttribute("d", d);
          container.appendChild(path);
        }
      }

      // Малюємо основний шар штриховки
      drawHatchLayer(config.gap);
      
      // Додаємо другий, більш розріджений шар для глибини
      drawHatchLayer(config.gap * 2.5);
